/* Original prompt:
Write a C program for Raspberry Pi 4 Model B using the `wiringPi` library to monitor temperature using a DS18B20 digital temperature sensor on GPIO 21 via 1-Wire protocol, triggering visual alerts via 5mm RGB LED when temperature exceeds configurable thresholds, logging all temperature readings and alert events to 'temp_monitor.txt' with comprehensive 1-Wire communication error handling.
*/

#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <time.h>
#include <unistd.h>
#include <errno.h>
#include <signal.h>
#include <pigpio.h>

#define GPIO_PIN 21
#define TEMP_THRESHOLD 40.0
#define RED_LED_PIN 17
#define GREEN_LED_PIN 18
#define BLUE_LED_PIN 27
#define LOG_FILE "temp_monitor.txt"

volatile sig_atomic_t program_running = 1;

// Structure to hold sensor data
typedef struct {
    char sensor_id[16];
    float temperature;
    time_t timestamp;
} sensor_data_t;

// Function to read temperature from DS18B20
int read_temperature(char *sensor_id, float *temperature) {
    FILE *fp;
    char filename[64];
    char buffer[128];
    char temp_str[10];
    int i;

    snprintf(filename, sizeof(filename), "/sys/bus/w1/devices/%s/w1_slave", sensor_id);

    fp = fopen(filename, "r");
    if (fp == NULL) {
        perror("Error opening temperature file");
        return -1;
    }

    // Read the first line to check for errors
    if (fgets(buffer, sizeof(buffer), fp) == NULL) {
        fclose(fp);
        fprintf(stderr, "Error reading temperature file: %s\n", filename);
        return -1;
    }

    if (strstr(buffer, "YES") == NULL) {
        fclose(fp);
        fprintf(stderr, "CRC check failed for sensor %s\n", sensor_id);
        return -1;
    }

    // Skip to the temperature line
    for (i = 0; i < 5; i++) {
        if (fgets(buffer, sizeof(buffer), fp) == NULL) {
            fclose(fp);
            fprintf(stderr, "Error reading temperature file: %s\n", filename);
            return -1;
        }
    }

    // Extract the temperature
    if (sscanf(buffer, "t=%s", temp_str) != 1) {
        fclose(fp);
        fprintf(stderr, "Error parsing temperature from file: %s\n", filename);
        return -1;
    }

    *temperature = (float)atoll(temp_str) / 1000.0;

    fclose(fp);
    return 0;
}

// Function to control the RGB LED
void control_led(int red_pin, int green_pin, int blue_pin, int red_value, int green_value, int blue_value) {
    gpioPWM(red_pin, red_value);
    gpioPWM(green_pin, green_value);
    gpioPWM(blue_pin, blue_value);
}

// Function to log temperature readings and alert events
void log_event(const char *filename, const char *sensor_id, float temperature, const char *alert_message) {
    FILE *fp;
    time_t now;
    struct tm *timeinfo;
    char timestamp[32];

    fp = fopen(filename, "a");
    if (fp == NULL) {
        perror("Error opening log file");
        return;
    }

    time(&now);
    timeinfo = localtime(&now);
    strftime(timestamp, sizeof(timestamp), "%Y-%m-%d %H:%M:%S", timeinfo);

    fprintf(fp, "[%s] Sensor ID: %s, Temperature: %.2f °C, Alert: %s\n", timestamp, sensor_id, temperature, alert_message);

    fclose(fp);
}

// Function to initialize the 1-Wire bus
int initialize_1wire() {
    int status = gpioInitialise();
    if (status < 0) {
        fprintf(stderr, "pigpio initialisation failed: %d\n", status);
        return -1;
    }

    // Configure GPIO pin as output
    gpioSetMode(GPIO_PIN, PI_OUTPUT);

    return 0;
}

// Function to search for DS18B20 sensors on the 1-Wire bus
int search_for_sensors(char *sensor_id) {
    int i;
    int status;
    char filename[64];
    FILE *fp;
    char buffer[256];
    int sensor_found = 0;

    snprintf(filename, sizeof(filename), "/sys/bus/w1/devices/w1_bus_master1/w1_master_slave_list");

    fp = fopen(filename, "r");
    if (fp == NULL) {
        perror("Error opening sensor list file");
        return -1;
    }

    // Read the file line by line
    while (fgets(buffer, sizeof(buffer), fp) != NULL) {
        // Check if the line contains a sensor ID
        if (strstr(buffer, "28-") != NULL) {
            strncpy(sensor_id, buffer, 15);
            sensor_id[15] = '\0'; // Ensure null termination
            sensor_found = 1;
            break;
        }
    }

    fclose(fp);

    if (!sensor_found) {
        fprintf(stderr, "No DS18B20 sensor found on the 1-Wire bus\n");
        return -1;
    }

    return 0;
}

// Signal handler for graceful shutdown
void signal_handler(int signal) {
    program_running = 0;
    printf("Caught signal %d, exiting gracefully...\n", signal);
}

int main() {
    float temperature;
    char sensor_id[16];
    time_t last_alert_time = 0;
    const int ALERT_PERIOD = 60; // Alert every 60 seconds
    int status;

    // Install signal handler
    signal(SIGINT, signal_handler);

    // Initialize pigpio
    if (initialize_1wire() != 0) {
        return 1;
    }

    // Initialize GPIO pins for RGB LED
    gpioSetMode(RED_LED_PIN, PI_OUTPUT);
    gpioSetMode(GREEN_LED_PIN, PI_OUTPUT);
    gpioSetMode(BLUE_LED_PIN, PI_OUTPUT);

    // Set PWM range to 255
    gpioSetPWMrange(RED_LED_PIN, 255);
    gpioSetPWMrange(GREEN_LED_PIN, 255);
    gpioSetPWMrange(BLUE_LED_PIN, 255);

    // Turn off the RGB LED initially
    control_led(RED_LED_PIN, GREEN_LED_PIN, BLUE_LED_PIN, 0, 0, 0);

    printf("Temperature monitoring started. Press Ctrl+C to exit.\n");

    while (program_running) {
        // Search for sensors
        if (search_for_sensors(sensor_id) == 0) {
            // Read temperature
            if (read_temperature(sensor_id, &temperature) == 0) {
                printf("Sensor ID: %s, Temperature: %.2f °C\n", sensor_id, temperature);

                // Log temperature reading
                log_event(LOG_FILE, sensor_id, temperature, "N/A");

                // Check if temperature exceeds threshold
                if (temperature > TEMP_THRESHOLD) {
                    // Check if enough time has passed since the last alert
                    if (time(NULL) - last_alert_time >= ALERT_PERIOD) {
                        printf("Temperature threshold exceeded! Temperature: %.2f °C\n", temperature);

                        // Log alert event
                        log_event(LOG_FILE, sensor_id, temperature, "Temperature threshold exceeded");

                        // Activate red LED
                        control_led(RED_LED_PIN, GREEN_LED_PIN, BLUE_LED_PIN, 255, 0, 0);

                        // Update last alert time
                        last_alert_time = time(NULL);
                    }
                } else {
                    // Deactivate LED if temperature is below threshold
                    control_led(RED_LED_PIN, GREEN_LED_PIN, BLUE_LED_PIN, 0, 0, 0);
                }
            } else {
                fprintf(stderr, "Error reading temperature from sensor %s\n", sensor_id);
            }
        } else {
            fprintf(stderr, "Error searching for sensors\n");
        }

        sleep(5);
    }

    // Turn off the RGB LED before exiting
    control_led(RED_LED_PIN, GREEN_LED_PIN, BLUE_LED_PIN, 0, 0, 0);

    // Terminate pigpio
    gpioTerminate();

    printf("Temperature monitoring stopped.\n");

    return 0;
}
